async def update_nutrition(user_text: str) -> tuple[str, list[str]]:
    """
    Run nutrition + micronutrient estimation for user_text, update nutrition_state
    in-place, save to disk, and return a (reply_text, response_parts) tuple.

    Callers pass their own prefix ("that's …", "logged. …") via response_parts[0]
    once this helper returns the computed nutrition dict.
    """
    nutrition = await asyncio.to_thread(estimate_nutrition_sync, user_text)
    micros = await asyncio.to_thread(estimate_micros_sync, user_text)

    if nutrition["calories"] == 0 and len(user_text.split()) < 5:
        return (
            "what exactly did you have? tell me the portions and i can track it properly.",
            [],
        )

    nutrition_state["calories"] += nutrition["calories"]
    nutrition_state["protein_g"] += nutrition["protein_g"]
    nutrition_state["water_liters"] += nutrition["water_liters"]
    tracked = set(nutrition_state.get("micros_tracked", []))
    tracked.update(micros)
    nutrition_state["micros_tracked"] = list(tracked)
    save_nutrition_state()

    micro_status = build_micro_status()
    response_parts: list[str] = []
    if "missing" in micro_status:
        response_parts.append(micro_status)

    return "", response_parts

